"use strict";(self.webpackChunkavstudio_docs=self.webpackChunkavstudio_docs||[]).push([[5259],{7247:e=>{e.exports=JSON.parse('{"tag":{"label":"avstudio","permalink":"/avstudio-docs/tags/avstudio","allTagsPath":"/avstudio-docs/tags","count":24,"items":[{"id":"documentation/user-interface/user-interface","title":"3 User interface","description":"The User Interface of AVgator Studio provides a user-friendly and","permalink":"/avstudio-docs/documentation/user-interface/"},{"id":"about/about","title":"About AVgator Studio (AVstudio)","description":"To create a user interface on HTML5 for a Crestron control system, you","permalink":"/avstudio-docs/about/"},{"id":"documentation/getting-started/2-3-accessing-the-application/2-3-accessing-the-application","title":"Accessing the Application","description":"Log in to AVstudio to begin building and managing your user interfaces. Whether you\'re starting a new project or continuing existing work, this guide walks you through the secure login process.","permalink":"/avstudio-docs/documentation/getting-started/2-3-accessing-the-application/"},{"id":"knowledge-base/autonomic/autonomic","title":"Autonomic Mirage Media Server Integration Guide","description":"Before We Start","permalink":"/avstudio-docs/knowledge-base/autonomic/"},{"id":"documentation/user-interface/3-9-data-sources/3-9-data-sources","title":"Data Sources Overview","description":"The Data Sources section in AVstudio allows you to connect your project to external APIs, WebSocket streams, or local mock data. These sources can be used to feed dynamic content into your pages and components. With support for data transformation, image preloading, and flexible HTTP or WebSocket configurations, data sources make it easy to integrate real-time and remote data into your AVstudio workflows.","permalink":"/avstudio-docs/documentation/user-interface/3-9-data-sources/"},{"id":"documentation/documentation","title":"Documentation","description":"Complete documentation for AV Studio","permalink":"/avstudio-docs/documentation/"},{"id":"knowledge-base/doorbird/doorbird","title":"DoorBird Intercoms Integration Guide","description":"Before We Start","permalink":"/avstudio-docs/knowledge-base/doorbird/"},{"id":"documentation/user-interface/3-10-functions/3-10-functions","title":"Functions Overview","description":"The Functions section in AVstudio allows you to define custom JavaScript logic that enhances your project\u2019s interactivity. Functions can be used to manipulate variables, trigger navigation, fetch data, publish signals, and control audio playback. With built-in code snippets, live testing, and support for arguments, functions offer a flexible way to add dynamic behaviors across your application.","permalink":"/avstudio-docs/documentation/user-interface/3-10-functions/"},{"id":"documentation/getting-started/getting-started","title":"Getting Started","description":"Get started with AVstudio","permalink":"/avstudio-docs/documentation/getting-started/"},{"id":"documentation/user-interface/3-7-global-containers/3-7-global-containers","title":"Global Containers Overview","description":"The Global Containers section in AVstudio lets you create persistent, reusable interface blocks that appear across multiple pages. Whether it\u2019s a navigation bar, footer, or overlay, global containers help ensure design consistency while giving you control over placement and visibility on a per-page basis.","permalink":"/avstudio-docs/documentation/user-interface/3-7-global-containers/"},{"id":"knowledge-base/how-to/button-with-a-gradient-or-an-image/button-with-a-gradient-or-an-image","title":"How to create button with a gradient","description":"Introduction","permalink":"/avstudio-docs/knowledge-base/how-to/button-with-a-gradient-or-an-image/"},{"id":"documentation/Introduction/introduction","title":"Introduction to AVstudio","description":"Welcome to AVstudio\u2014your gateway to designing dynamic and interactive user interfaces with professional precision. AVstudio (also known as AVgator Studio) is a powerful HTML5 GUI editor that enables developers of all levels to create, customize, and manage rich interfaces for control systems. Whether you prefer a cloud-based platform or a compiled desktop solution, AVstudio adapts to your workflow with seamless cross-platform compatibility and robust feature sets.","permalink":"/avstudio-docs/documentation/Introduction/"},{"id":"documentation/user-interface/3-1-main-dashboard/3-1-main-dashboard","title":"Main Dashboard Overview","description":"The Main Dashboard is the first screen you\u2019ll see after logging into AVstudio. It gives you a snapshot of your projects, templates, and settings. This overview will walk you through each area of the interface so you can navigate and manage your work with confidence.","permalink":"/avstudio-docs/documentation/user-interface/3-1-main-dashboard/"},{"id":"documentation/user-interface/3-11-media-assets/3-11-media-assets","title":"Media Assets Overview","description":"The Media Assets panel is where you can upload and manage images, fonts, and audio files for use in your AVstudio project.","permalink":"/avstudio-docs/documentation/user-interface/3-11-media-assets/"},{"id":"knowledge-base/multilanguage/multilanguage","title":"Multi-Language Implementation Guide","description":"Before We Start","permalink":"/avstudio-docs/knowledge-base/multilanguage/"},{"id":"documentation/user-interface/3-5-pages/3-5-pages","title":"Pages Overview","description":"The Pages section in AVstudio is where you manage the main views of your project. From selecting layout paradigms to configuring signal-based navigation, this interface helps you create, edit, and organize the pages that structure your application.","permalink":"/avstudio-docs/documentation/user-interface/3-5-pages/"},{"id":"documentation/getting-started/2-4-password-recovery/2-4-password-recovery","title":"Password Recovery","description":"If you\'ve lost access to your AVstudio account or can\'t remember your password, this guide will walk you through the password reset process.","permalink":"/avstudio-docs/documentation/getting-started/2-4-password-recovery/"},{"id":"documentation/user-interface/3-3-project-dashboard/3-3-project-dashboard","title":"Project Dashboard Overview","description":"The Project Dashboard is where you manage your individual projects in AVstudio. It gives you access to project-specific actions like previewing, building, cloning, deleting, and modifying settings \u2014 all within a single view.","permalink":"/avstudio-docs/documentation/user-interface/3-3-project-dashboard/"},{"id":"documentation/user-interface/3-4-project-settings/3-4-project-settings","title":"Project Settings Overview","description":"The Project Settings panel is where you configure key properties of your AVstudio project \u2014 from the project name and theme to environment-specific build settings and connector integrations.","permalink":"/avstudio-docs/documentation/user-interface/3-4-project-settings/"},{"id":"documentation/user-interface/3-8-project-variables/3-8-project-variables","title":"Project Variables Overview","description":"The Project Variables section in AVstudio lets you define and manage custom variables that store dynamic values. These variables can be used to control logic, respond to signals, and trigger actions across your project. With support for default values, signal feedback, and formatter functions, project variables give you flexible control over your application\u2019s behavior.","permalink":"/avstudio-docs/documentation/user-interface/3-8-project-variables/"},{"id":"documentation/user-interface/3-6-subpages/3-6-subpages","title":"Subpages Overview","description":"The Subpages section in AVstudio allows you to create supporting views that complement your main pages. Subpages follow the same layout paradigms as pages and are ideal for building modular, reusable screen components within your project.","permalink":"/avstudio-docs/documentation/user-interface/3-6-subpages/"},{"id":"documentation/getting-started/2-1-system-requirements/2-1-system-requirements","title":"System Requirements","description":"This article outlines the hardware, software, and network requirements needed to run AVstudio smoothly. Whether you\'re using the cloud-based SAAS platform or the compiled GUI environment, make sure your setup meets the following system specifications.","permalink":"/avstudio-docs/documentation/getting-started/2-1-system-requirements/"},{"id":"documentation/user-interface/3-2-user-profile-dashboard/3-2-user-profile-dashboard","title":"User Profile Dashboard Overview","description":"From the AVstudio main dashboard, clicking the profile icon in the upper-right corner gives you access to account-related actions like managing your profile or switching accounts. This page covers what you\u2019ll see and do in the User Profile Dashboard.","permalink":"/avstudio-docs/documentation/user-interface/3-2-user-profile-dashboard/"},{"id":"documentation/getting-started/2-2-user-registration-and-account-setup/2-2-user-registration-and-account-setup","title":"User Registration and Account Setup","description":"Start your journey with AVstudio by setting up a secure and personalized account. This guide walks you through registration, verification, and initial setup so you can begin building interfaces in minutes. \ud83d\ude80","permalink":"/avstudio-docs/documentation/getting-started/2-2-user-registration-and-account-setup/"}],"unlisted":false}}')}}]);